command:
// Fantasy performance-enhancing — battle-rage red glow that pulses.
// DAE Active Effect macro.execute callback.
// args = ["on"|"off", lastArg] where lastArg has { actor, actorUuid, tokenId, tokenUuid, effectId, ... }
if (!game.modules.get("tokenmagic")?.active) return;
const state = args?.[0];
const lastArg = args?.[args.length - 1];
const token = canvas.tokens.get(lastArg?.tokenId) ?? canvas.tokens.controlled[0];
if (!token) return;
const filterId = "fishut-tmfx-fantasy-performance-enhancing";
if (state === "off") { await TokenMagic.deleteFiltersOnToken(token, filterId); return; }
await TokenMagic.addUpdateFiltersOnToken(token, [{
  filterType: "glow",
  filterId,
  color: 0xcc2200,
  distance: 12,
  outerStrength: 5,
  innerStrength: 1,
  quality: 0.5,
  padding: 10,
  animated: { distance: { active: true, loopDuration: 1800, animType: "syncCosOscillation", val1: 8, val2: 14 } }
}]);
